from __future__ import annotations

from pathlib import Path


def build_system_prompt() -> str:
    return (
        "You are analyzing traces generated by a Moran process. "
        "Each row represents one birth-death event. "
        "Fields include event, mutants_before, mutants_after, and the constant population size N. "
        "Infer the initial mutant count i0 and relative fitness r as carefully as possible. "
        "Because the process is stochastic, do not assume exact identifiability from a partial trace. "
        "Return strict JSON with keys: estimated_i0, estimated_r, confidence, reasoning_summary."
    )


def build_user_prompt_from_csv(csv_path: str | Path) -> str:
    csv_path = Path(csv_path)
    csv_content = csv_path.read_text(encoding="utf-8")
    return (
        f"Trace file: {csv_path.name}\n"
        "Below is a Moran-process event trace in CSV format. "
        "Use the data itself, including the N column, rather than assuming a fixed population size.\n\n"
        f"{csv_content}"
    )
